query Node($id: String!) {
  node(id: $id) {
    id
    state
    version
    updatedAt
  }
}

query Runs($limit: Int!) {
  runs(limit: $limit) {
    id
    target
    kind
    status
    completedSteps
    startedAt
    finishedAt
