}

query Advise($nodeId: String!, $context: String!) {
  advise(nodeId: $nodeId, context: $context)
}

request.description:
Live ops event stream over the graphql-transport-ws protocol. Open a WebSocket request in Postman to ws://localhost:8080/graphql/ws and send:

subscription {
  opsEvents { kind payload }
}

Events: run_started, step_completed, step_compensated, node_state_changed, health_evaluated, run_finished. Each subscriber gets an independent broadcast stream.
